CREATE OR REPLACE FUNCTION fpa_gos_receipt_loan_bal (as_recno char,as_conno char) RETURNS bigint AS $body$
DECLARE

  ldc_value bigint;

BEGIN
  select sc_com_m_receipt_item.balance into STRICT ldc_value
  from sc_com_m_receipt
  ,sc_com_m_receipt_item
  where (sc_com_m_receipt_item.receipt_no = sc_com_m_receipt.receipt_no)
  and (sc_com_m_receipt.receipt_status = '0')
  and (trim(both sc_com_m_receipt.receipt_no) = as_recno)
  and (trim(both sc_com_m_receipt_item.description) = as_conno);

  return ldc_value;

exception
when no_data_found then return 0;
when others then CALL spa_dberror('fpa_gos_receipt_loan_bal');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
